#include <stdio.h>
#include <stdint.h>

static inline uint64_t digital_root(uint64_t x) {
    uint64_t r = x % 9ULL;
    return r == 0ULL ? 9ULL : r;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        uint64_t A1, D, L, R;
        scanf("%llu %llu %llu %llu", &A1, &D, &L, &R);
        uint64_t len = R - L + 1ULL;
        uint64_t d_mod = D % 9ULL;
        uint64_t p = (d_mod == 0ULL) ? 1ULL : 9ULL / __gcd(d_mod, 9ULL);
        uint64_t period[9];
        uint64_t start = A1 + (L - 1ULL) * D;
        uint64_t cur = start;
        for (uint64_t i = 0; i < p; ++i) {
            period[i] = digital_root(cur);
            cur += D;
        }
        uint64_t sumPeriod = 0ULL;
        for (uint64_t i = 0; i < p; ++i) sumPeriod += period[i];
        uint64_t full = len / p;
        uint64_t rem = len % p;
        uint64_t ans = full * sumPeriod;
        for (uint64_t i = 0; i < rem; ++i) ans += period[i];
        printf("%llu\n", ans);
    }
    return 0;
}

