import java.io.*;
import java.util.*;

public class Main {
    private static long dr(long x){
        long r = x % 9L;
        return r == 0L ? 9L : r;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for(int tc=0; tc<T; ++tc){
            StringTokenizer st = new StringTokenizer(br.readLine());
            long A1 = Long.parseLong(st.nextToken());
            long D  = Long.parseLong(st.nextToken());
            long L  = Long.parseLong(st.nextToken());
            long R  = Long.parseLong(st.nextToken());
            long len = R - L + 1L;
            long dmod = D % 9L;
            long p = (dmod == 0L) ? 1L : 9L / gcd(dmod, 9L);
            long[] period = new long[(int)p];
            long cur = A1 + (L-1L)*D;
            for(int i=0;i<p;i++){
                period[i] = dr(cur);
                cur += D;
            }
            long sumPeriod = 0L;
            for(long v: period) sumPeriod += v;
            long full = len / p;
            long rem = len % p;
            long ans = full * sumPeriod;
            for(int i=0;i<rem;i++) ans += period[i];
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
    private static long gcd(long a, long b){
        while(b!=0){ long t=a%b; a=b; b=t; }
        return a;
    }
}

